import 'dart:convert'; import 'package:dio/dio.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../cart/presentation/providers/cart_providers.dart'; import '../domain/entities/checkout_suggestions.dart';
final checkoutSuggestionsProvider=FutureProvider<CheckoutSuggestions>((ref)async{try{final response=await ref.watch(cartDioProvider).get<dynamic>('/wp-json/woo-mobile/v1/checkout-config',options:Options(headers:const{'Cache-Control':'no-cache'}));final data=response.data is String?jsonDecode(response.data as String):response.data;if(data is Map&&data['suggestions'] is Map){return CheckoutSuggestions.fromJson(Map<String,dynamic>.from(data['suggestions'] as Map));}}catch(_){ }return const CheckoutSuggestions();});
